SELECT profile_id, profile_name
FROM profiles
ORDER BY last_updated DESC;

SELECT default_bit_depth
FROM profile_bit_depths
WHERE profile_id = 0;

SELECT chroma_format_value, description
FROM chroma_formats
WHERE chroma_format_id = 1;

SELECT profile_name, version
FROM profiles
ORDER BY version DESC;

SELECT COUNT(profile_id) AS adopted_profiles_count
FROM profile_features
WHERE feature_id = 1 AND supported = 1;
